// Odbierz dane z webhooka ClickUp
const body = $json.body || $json;

// ClickUp wysyła event przy zmianie statusu
const eventType = body.event;
const taskData = body.task_id ? body : (body.history_items?.[0] || {});

// Pobierz ID taska i nowy status
const taskId = body.task_id || taskData.task?.id;
const newStatus = body.history_items?.[0]?.after?.status?.toLowerCase() || 
                  body.status?.toLowerCase() || 
                  '';

// Sprawdź czy to zdarzenie zmiany statusu
const isStatusChange = eventType === 'taskStatusUpdated' || 
                       body.history_items?.[0]?.field === 'status';

// Sprawdź czy nowy status to 'zakończone'
// WAŻNE: Zmień 'done' na dokładną nazwę Twojego statusu!
const targetStatuses = ['done', 'zakończone', 'complete', 'closed', 'zakonczone'];
const isCompleted = targetStatuses.some(s => newStatus.includes(s));

console.log(`Task ID: ${taskId}, Status: ${newStatus}, IsCompleted: ${isCompleted}`);

return [{
  json: {
    task_id: taskId,
    new_status: newStatus,
    is_completed: isCompleted,
    is_status_change: isStatusChange,
    raw_event: eventType
  }
}];

// Przygotuj dane do skopiowania do archiwum
const task = $json;
const now = new Date();
const dateStr = now.toLocaleDateString('pl-PL', {
  day: '2-digit',
  month: '2-digit',
  year: 'numeric'
});
const timeStr = now.toLocaleTimeString('pl-PL', {
  hour: '2-digit',
  minute: '2-digit'
});

// Przygotuj custom fields do skopiowania
const customFields = task.custom_fields?.map(field => {
  // Pomijamy pola bez wartości
  if (field.value === null || field.value === undefined) return null;
  return {
    id: field.id,
    value: field.value
  };
}).filter(Boolean) || [];

// Buduj obiekt nowego taska w archiwum
const archiveTask = {
  name: `[ARCHIWUM ${dateStr}] ${task.name}`,
  description: `## Zarchiwizowano: ${dateStr} o ${timeStr}\n\n${task.description || 'Brak opisu'}\n\n---\n**Oryginalny Task ID:** ${task.id}\n**Data zakończenia:** ${dateStr} ${timeStr}`,
  status: 'Open',
  priority: task.priority?.id || 3,
  custom_fields: customFields,
  tags: [...(task.tags?.map(t => t.name) || []), 'archiwum', dateStr]
};

return [{
  json: {
    archive_task: archiveTask,
    original_task_id: task.id,
    original_task_name: task.name,
    original_list_id: task.list?.id,
    archived_at: now.toISOString()
  }
}];

// Sprawdź czy archiwizacja się powiodła
const archivedTask = $json;
const prevData = $('Przygotuj Task do Archiwum').first().json;

if (!archivedTask.id) {
  throw new Error(`Błąd archiwizacji taska: ${prevData.original_task_id}`);
}

console.log(`Zarchiwizowano: ${prevData.original_task_name} → ${archivedTask.id}`);

return [{
  json: {
    success: true,
    original_task_id: prevData.original_task_id,
    archive_task_id: archivedTask.id,
    archive_task_url: archivedTask.url,
    archived_at: prevData.archived_at
  }
}];

