// Pobierz wszystkie taski-szablony
const response = $json;
const templates = response.tasks || [];

if (templates.length === 0) {
  throw new Error('Brak szablonow w liscie! Sprawdz TWOJA_LISTA_SZABLONOW_ID');
}

console.log(`Znaleziono ${templates.length} szablonow`);

// Przygotuj datę
const today = new Date();
const dateStr = today.toLocaleDateString('pl-PL', {
  day: '2-digit',
  month: '2-digit',
  year: 'numeric'
});

// Dla każdego szablonu stwórz obiekt nowego taska
const newTasks = templates.map(template => {

  // Skopiuj custom fields (tylko te z wartościami)
  const customFields = (template.custom_fields || []).map(field => {
    if (field.value === null || field.value === undefined) return null;
    return { id: field.id, value: field.value };
  }).filter(Boolean);

  return {
    json: {
      // Nowa nazwa z datą
      name: `${template.name} - ${dateStr}`,

      // Opis z info o szablonie
      description: `${template.description || ''}\n\n---\nUtworzono z szablonu: ${template.name}\nData: ${dateStr}`,

      // Status początkowy
      status: 'Open',

      // Priorytet z szablonu
      priority: template.priority?.id || 3,

      // Custom fields z szablonu
      custom_fields: customFields,

      // Tagi z szablonu + tag z datą
      tags: [
        ...(template.tags?.map(t => t.name) || []),
        dateStr
      ],

      // Zachowaj assignees z szablonu
      assignees: template.assignees?.map(a => a.id) || [],

      // Meta do logowania (nie idzie do ClickUp)
      _template_id: template.id,
      _template_name: template.name
    }
  };
});

console.log(`Przygotowano ${newTasks.length} taskow do utworzenia`);

return newTasks;

// Usuń meta pola przed wysłaniem do ClickUp
const item = $json;

const taskPayload = {
  name: item.name,
  description: item.description,
  status: item.status,
  priority: item.priority,
  custom_fields: item.custom_fields,
  tags: item.tags,
  assignees: item.assignees
};

// Zachowaj meta do logowania
return [{
  json: {
    payload: taskPayload,
    _template_id: item._template_id,
    _template_name: item._template_name
  }
}];

// Loguj każdy utworzony task
const createdTask = $json;
const templateName = $('Przygotuj Payload').first().json._template_name;
const now = new Date().toISOString();

console.log(`[OK] ${templateName} → Task ID: ${createdTask.id}`);

return [{
  json: {
    success: true,
    template_name: templateName,
    new_task_id: createdTask.id,
    new_task_name: createdTask.name,
    new_task_url: createdTask.url,
    created_at: now
  }
}];

// Zbierz wszystkie wyniki z całego batcha
const allItems = $input.all();

const summary = {
  total_created: allItems.length,
  created_at: new Date().toISOString(),
  tasks: allItems.map(item => ({
    template: item.json.template_name,
    task_id: item.json.new_task_id,
    task_url: item.json.new_task_url
  }))
};

console.log(`=== PODSUMOWANIE ===`);
console.log(`Utworzono ${summary.total_created} taskow`);
console.log(JSON.stringify(summary, null, 2));

return [{ json: summary }];
